import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, HealingResult, ProjectContext } from "../../base.ts";

/**
 * ⚙️ Dr. Hermes — PhD in Environment Safety & Secret Delivery (TypeScript)
 * Generated by Sovereign Forge.
 */
export class HermesPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "hermes";
        this.name = "Hermes";
        this.emoji = "⚙️";
        this.role = "PhD DevOps & SRE Engineer";
        this.phd_identity = "Environment Safety & Secret Delivery (TypeScript)";
        this.stack = "Bun";
        this.healingPrompt = "Fix the following messaging or event-driven architecture issue. Ensure correct message schemas, dead-letter handling, and idempotency. Return ONLY the corrected code or a specific diff.";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        if (this.healingPrompt) {
            const { findings } = await this.auditAndHeal();
            return findings;
        }
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "DEBUG\\s*=\\s*true",
                    "issue": "Ambiente: Flag DEBUG ativa — risco em produção PhD.",
                    "severity": "high"
          },
          {
                    "regex": "NODE_ENV\\s*[!=]==?\\s*[\"']development",
                    "issue": "Condicional de Ambiente: Lógica bifurcada por NODE_ENV — verifique segurança PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "process\\.env\\.[A-Z_]+(?!\\s*\\?)(?!.*\\|\\|)(?!.*[\\?][\\?])(?!.*throw)",
                    "issue": "Variável Frágil: process.env sem fallback ou validação PhD.",
                    "severity": "medium"
          },
          {
                    "regex": "dotenv\\.config\\(\\)",
                    "issue": "Risco: dotenv carregando .env — garanta que .env não está no Git PhD.",
                    "severity": "low"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Hermes operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Hermes, PhD em Environment Safety & Secret Delivery (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
